import { Dispatch, SetStateAction, useEffect, useRef, useState } from "react";
import { localCache } from "../tool";
import { RouteObject, matchRoutes, useLocation } from "react-router-dom";

/**
 * 配合 useState 来自动更新缓存
 * @param key 在独立的路由下不重复即可，生成时会使用 routeKey
 * @param defaultValue 等同于 useState(defaultValue)
 * @TODO 数据结构存在问题时的兜底方案
 */
export const useStateWithLocalCache = <
    S extends string | number | boolean | any[] | Record<string, any>,
>(
    key: string,
    defaultValue: SetStateAction<S>,
    routes: RouteObject[],
): [S, Dispatch<SetStateAction<S>>] => {
    const location = useLocation();
    const matchedRoutes = matchRoutes(routes, { pathname: location.pathname });
    const routeKey = matchedRoutes?.[matchedRoutes?.length - 1]?.pathname?.split('/').join('-');
    const _k = routeKey ? `${routeKey}_${key}` : null;
    const [state, setState] = useState<S>((_k && localCache.get(_k)) || defaultValue);

    useEffect(() => {
        if (_k) {
            localCache.set(_k, state);
        }
    }, [state]);
    return [state, setState];
};

/**
 * 单纯的使用缓存，缓存的存取不会驱动视图更新
 * @param key 在独立的路由下不重复即可，生成时会使用 routeKey
 * @param defaultValue
 * @TODO 数据结构存在问题时的兜底方案
 */
export const useLocalCache = <S extends string | number | boolean | any[] | Record<string, any>>(
    key: string,
    defaultValue: SetStateAction<S>,
    routes: RouteObject[],
    location: ReturnType<typeof useLocation>,
) => {
    const matchedRoutes = matchRoutes(routes, { pathname: location.pathname });
    const routeKey = matchedRoutes?.[matchedRoutes?.length - 1]?.pathname
        ?.split('/')
        .filter((path) => !!path)
        .join('_');
    const _k = (routeKey ? `${routeKey}_${key}` : `${key}`).toUpperCase();
    const cache = useRef<S>((_k && localCache.get(_k)) || defaultValue);

    const setCache = (data: S) => {
        if (_k) {
            localCache.set(_k, data);
        }
    };
    const getCache = () => cache.current;

    return { getCache, setCache, cacheKey: _k };
};
